# ---------------------------------------------------------------------------
# Helper to build 8-agent chatter list consistently
# ---------------------------------------------------------------------------

def _build_chatter(
    ic_msg: str, ic_tools: list[str], ic_act: str,
    mc_msg: str, mc_tools: list[str], mc_act: str,
    fc_msg: str, fc_tools: list[str], fc_act: str,
    tp_msg: str, tp_tools: list[str], tp_act: str,
    tw_msg: str, tw_tools: list[str], tw_act: str,
    sl_msg: str, sl_tools: list[str], sl_act: str,
    pi_msg: str, pi_tools: list[str], pi_act: str,
    hz_msg: str, hz_tools: list[str], hz_act: str,
) -> list[dict[str, Any]]:
    return [
        {
            "agent": "Incident Commander", "emoji": "🧑‍✈️", "status": "ACTIVE",
            "message": ic_msg, "tools_used": ic_tools, "last_action": ic_act,
        },
        {
            "agent": "Medical Coordinator", "emoji": "🚑", "status": "ACTIVE",
            "message": mc_msg, "tools_used": mc_tools, "last_action": mc_act,
        },
        {
            "agent": "Fire Chief", "emoji": "🚒", "status": "ACTIVE",
            "message": fc_msg, "tools_used": fc_tools, "last_action": fc_act,
        },
        {
            "agent": "Traffic Planner", "emoji": "🚦", "status": "ACTIVE",
            "message": tp_msg, "tools_used": tp_tools, "last_action": tp_act,
        },
        {
            "agent": "Tactical Weather Analyst", "emoji": "🌦️", "status": "ACTIVE",
            "message": tw_msg, "tools_used": tw_tools, "last_action": tw_act,
        },
        {
            "agent": "Strategic Logistics Officer", "emoji": "📦", "status": "ACTIVE",
            "message": sl_msg, "tools_used": sl_tools, "last_action": sl_act,
        },
        {
            "agent": "Public Information Officer", "emoji": "📢", "status": "ACTIVE",
            "message": pi_msg, "tools_used": pi_tools, "last_action": pi_act,
        },
        {
            "agent": "HAZMAT Specialist", "emoji": "☢️", "status": "ACTIVE",
            "message": hz_msg, "tools_used": hz_tools, "last_action": hz_act,
        },
    ]

