# ---------------------------------------------------------------------------
# Master Matrix & Selector
# ---------------------------------------------------------------------------

CRISIS_MATRIX: dict[str, list[dict[str, Any]]] = {
    "earthquake": EARTHQUAKE_SCENARIOS,
    "flood": FLOOD_SCENARIOS,
    "grid": GRID_SCENARIOS,
    "hazmat": HAZMAT_SCENARIOS,
    "hurricane": HURRICANE_SCENARIOS,
    "cyber": CYBER_SCENARIOS,
}


def get_random_scenario(disaster_type: Optional[str] = None) -> dict[str, Any]:
    """
    Select and return a randomized sub-scenario from the requested disaster track.
    If disaster_type is missing or not in CRISIS_MATRIX, randomly select any track.
    """
    if not disaster_type or disaster_type.lower() not in CRISIS_MATRIX:
        disaster_type = random.choice(list(CRISIS_MATRIX.keys()))
    else:
        disaster_type = disaster_type.lower()

    scenarios = CRISIS_MATRIX[disaster_type]
    selected = random.choice(scenarios)

    # Return a deep-ish copy / formatted dict ready for Supabase persistence
    return {
        "disaster_type": disaster_type,
        "emergency_level": selected.get("emergency_level", "CRITICAL"),
        "timeline_text": selected.get("timeline_text", ""),
        "agent_chatter": selected.get("chatter", []),
        "action_plan": selected.get("plan", []),
    }


def infer_disaster_type_from_text(text: str) -> Optional[str]:
    """
    Helper to infer disaster category from event text keywords if not explicitly passed.
    """
    if not text:
        return None
    lower_text = text.lower()
    if any(k in lower_text for k in ["seismic", "earthquake", "quake", "tremor", "fault", "usgs"]):
        return "earthquake"
    if any(k in lower_text for k in ["dam ", " dam", "hydrological", "flood", "levee", "spillway", "tsunami", "aqueduct"]):
        return "flood"
    if any(k in lower_text for k in ["grid", "blackout", "power", "substation", "transformer", "voltage", "nerc", "iso"]):
        return "grid"
    if any(k in lower_text for k in ["hazmat", "chemical", "chlorine", "ammonia", "acid", "vapor", "plume", "toxic", "spill", "benzene", "acrylonitrile"]):
        return "hazmat"
    if any(k in lower_text for k in ["hurricane", "cyclone", "eyewall", "storm surge", "cat 5", "category 5", "wind gust", "landfall"]):
        return "hurricane"
    if any(k in lower_text for k in ["cyber", "ransomware", "scada", "malware", "hack", "encryption", "ddos", "tdos", "spoof", "phishing"]):
        return "cyber"
    return None
